html:
{% set doc = doc %}
{% set pc = (doc.flags.get('order_sheet_print_columns') or []) if doc.flags else [] %}
{% set fs = doc.flags.get('order_sheet_print_footer_start', 0) if doc.flags else 0 %}
{% set fm = doc.flags.get('order_sheet_print_footer_totals_map') if doc.flags else {} %}
{% set parent_meta = frappe.get_meta(doc.doctype) %}
{% set left_types = ['Data', 'Text', 'Small Text', 'Text Editor', 'Link', 'Long Text', 'Code'] %}
{% set ncol = 1 + (pc | length) %}
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    font-family: 'Arial Narrow', Arial, sans-serif;
    font-size: 9pt;
    color: #1a1a1a;
    background: #fff;
  }

  .page {
    width: 100%;
    padding: 12mm 10mm;
  }

  /* ── HEADER ── */
  .header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    border-bottom: 3px solid #1a1a2e;
    padding-bottom: 8px;
    margin-bottom: 10px;
  }

  .header-left .doc-title {
    font-size: 20pt;
    font-weight: 900;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: #1a1a2e;
    line-height: 1;
  }

  .header-left .doc-name {
    font-size: 10pt;
    color: #666;
    margin-top: 3px;
    letter-spacing: 1px;
  }

  .header-right {
    text-align: right;
  }

  .header-right .company-name {
    font-size: 13pt;
    font-weight: 700;
    color: #1a1a2e;
    letter-spacing: 1px;
  }

  /* ── META INFO GRID ── */
  .meta-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 0;
    border: 1px solid #c0c0c0;
    margin-bottom: 10px;
  }

  .meta-cell {
    padding: 5px 8px;
    border-right: 1px solid #c0c0c0;
  }

  .meta-cell:last-child { border-right: none; }

  .meta-cell .label {
    font-size: 6.5pt;
    text-transform: uppercase;
    letter-spacing: 0.8px;
    color: #888;
    font-weight: 700;
    margin-bottom: 2px;
  }

  .meta-cell .value {
    font-size: 9pt;
    font-weight: 600;
    color: #1a1a2e;
  }

  .meta-cell .value.large {
    font-size: 11pt;
    font-weight: 700;
  }

  /* ── SECTION HEADINGS ── */
  .section-heading {
    background: #1a1a2e;
    color: #fff;
    font-size: 7pt;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    font-weight: 700;
    padding: 4px 8px;
    margin-bottom: 0;
  }

  /* ── ORDER TABLE ── */
  table.order-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 10px;
    font-size: 7.5pt;
  }

  table.order-table thead tr {
    background: #2d3561;
    color: #fff;
  }

  table.order-table thead th {
    padding: 5px 4px;
    text-align: center;
    font-size: 6.5pt;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-weight: 700;
    border: 1px solid #1a1a2e;
    white-space: nowrap;
  }

  table.order-table thead th.left { text-align: left; }

  table.order-table tbody tr:nth-child(even) {
    background: #f4f6fb;
  }

  table.order-table tbody tr:hover {
    background: #e8ecf8;
  }

  table.order-table tbody td {
    padding: 4px 4px;
    border: 1px solid #d4d8e8;
    text-align: center;
    vertical-align: middle;
    color: #222;
  }

  table.order-table tbody td.left { text-align: left; }

  table.order-table tfoot tr {
    background: #1a1a2e;
    color: #fff;
    font-weight: 700;
  }

  table.order-table tfoot td {
    padding: 5px 4px;
    border: 1px solid #0d0d1a;
    text-align: center;
    font-size: 7.5pt;
  }

  table.order-table tfoot td.left { text-align: left; }

  /* ── TOTALS BOX ── */
  .totals-wrapper {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
    margin-bottom: 10px;
  }

  .totals-box {
    border: 1px solid #c0c0c0;
  }

  .totals-box .box-title {
    background: #2d3561;
    color: #fff;
    font-size: 6.5pt;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: 700;
    padding: 4px 8px;
  }

  .totals-box table {
    width: 100%;
    border-collapse: collapse;
  }

  .totals-box table tr:nth-child(even) td {
    background: #f4f6fb;
  }

  .totals-box table td {
    padding: 4px 8px;
    border-bottom: 1px solid #e0e0e0;
    font-size: 8pt;
  }

  .totals-box table td:first-child {
    color: #666;
    font-size: 7pt;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    width: 60%;
  }

  .totals-box table td:last-child {
    font-weight: 700;
    text-align: right;
    color: #1a1a2e;
  }

  /* ── INSTRUCTIONS ── */
  .instructions-box {
    border: 1px solid #c0c0c0;
    margin-bottom: 10px;
  }

  .instructions-box .box-title {
    background: #2d3561;
    color: #fff;
    font-size: 6.5pt;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: 700;
    padding: 4px 8px;
  }

  .instructions-box .box-content {
    padding: 8px;
    font-size: 8pt;
    color: #333;
    min-height: 30px;
    line-height: 1.5;
  }

  /* ── FOOTER ── */
  .doc-footer {
    border-top: 2px solid #1a1a2e;
    padding-top: 6px;
    display: flex;
    justify-content: space-between;
    font-size: 7pt;
    color: #999;
  }

  /* ── STATUS BADGE ── */
  .status-badge {
    display: inline-block;
    padding: 2px 8px;
    font-size: 7pt;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
    border-radius: 2px;
  }

  .badge-draft     { background: #e0e0e0; color: #555; }
  .badge-submitted { background: #d4edda; color: #155724; }
  .badge-cancelled { background: #f8d7da; color: #721c24; }

  /* Print */
  @media print {
    body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
    .page { padding: 10mm 8mm; }
  }
</style>
</head>
<body>
<div class="page">

  <div class="header">
    <div class="header-left">
      <div class="doc-title">Order Sheet</div>
      <div class="doc-name">{{ doc.name }}</div>
    </div>
    <div class="header-right">

      <div style="margin-top:4px;">
        {% if doc.docstatus == 0 %}
          <span class="status-badge badge-draft">Draft</span>
        {% elif doc.docstatus == 1 %}
          <span class="status-badge badge-submitted">Submitted</span>
        {% else %}
          <span class="status-badge badge-cancelled">Cancelled</span>
        {% endif %}
      </div>
    </div>
  </div>

  <div class="meta-grid">
    <div class="meta-cell">
      <div class="label">Order No</div>
      <div class="value large">{{ doc.order_no or '—' }}</div>
    </div>
    <div class="meta-cell">
      <div class="label">Customer</div>
      <div class="value large">{{ doc.customer or '—' }}</div>
    </div>
    <div class="meta-cell">
      <div class="label">Shipment Date</div>
      <div class="value large">{{ frappe.format_date(doc.shipment_date) }}</div>
    </div>
    <div class="meta-cell">
      <div class="label">Port of Destination</div>
      <div class="value large">{{ doc.port_of_destination or '—' }}</div>
    </div>
  </div>


  <div class="section-heading">Order Details</div>
  <table class="order-table">
    <thead>
      <tr>
        <th style="width:3%;">#</th>
        {% for df in pc %}
        <th class="{% if df.fieldtype in left_types %}left{% endif %}">{{ df.label }}</th>
        {% endfor %}
      </tr>
    </thead>
    <tbody>
      {% for row in doc.order_sheet_ct %}
      <tr>
        <td>{{ loop.index }}</td>
        {% for df in pc %}
        <td class="{% if df.fieldtype in left_types %}left{% endif %}">
          {% set raw = row.get(df.fieldname) %}
          {% if raw is none or raw == '' %}
            —
          {% else %}
            {{ frappe.format_value(raw, df) }}
          {% endif %}
        </td>
        {% endfor %}
      </tr>
      {% else %}
      <tr>
        <td colspan="{{ ncol }}" style="text-align:center; color:#999; padding:12px;">No order lines found.</td>
      </tr>
      {% endfor %}
    </tbody>
    {% if pc and doc.order_sheet_ct %}
    <tfoot>
      <tr>
        <td></td>
        {% if fs > 0 %}
        <td class="left" colspan="{{ fs }}">TOTALS</td>
        {% endif %}
        {% for df in pc[fs:] %}
        <td>
          {% set fk = fm.get(df.fieldname) if fm else none %}
          {% if fk %}
            {% set pdf = parent_meta.get_field(fk) %}
            {{ frappe.format_value(doc.get(fk), pdf) }}
          {% else %}
            —
          {% endif %}
        </td>
        {% endfor %}
      </tr>
    </tfoot>
    {% endif %}
  </table>

  <div class="totals-wrapper">
    <div class="totals-box">
      <div class="box-title">Order Totals</div>
      <table>
        <tr>
          <td>Total Quantity</td>
          <td>{{ doc.total_quantity | round(2) if doc.total_quantity else '0' }}</td>
        </tr>
        <tr>
          <td>Total Carton</td>
          <td>{{ doc.total_cartoon | round(2) if doc.total_cartoon else '0' }}</td>
        </tr>
        <tr>
          <td>Total Qty / Carton</td>
          <td>{{ doc.total_quantity_per_cartoon | round(2) if doc.total_quantity_per_cartoon else '0' }}</td>
        </tr>
        <tr>
          <td>Total Consumption</td>
          <td>{{ doc.total_consumption | round(4) if doc.total_consumption else '0' }}</td>
        </tr>
      </table>
    </div>

    <div class="totals-box">
      <div class="box-title">Logistics Totals</div>
      <table>
        <tr>
          <td>Total Order CBM</td>
          <td>{{ doc.total_order_cbm | round(4) if doc.total_order_cbm else '0' }}</td>
        </tr>
        <tr>
          <td>Total Net Weight (KG)</td>
          <td>{{ doc.total_net_weight | round(3) if doc.total_net_weight else '0' }}</td>
        </tr>
        <tr>
          <td>Total Gross Weight (KG)</td>
          <td>{{ doc.total_gross_weight | round(3) if doc.total_gross_weight else '0' }}</td>
        </tr>
      </table>
    </div>
  </div>

  {% if doc.instructions %}
  <div class="instructions-box">
    <div class="box-title">Instructions</div>
    <div class="box-content">{{ doc.instructions }}</div>
  </div>
  {% endif %}

  <div class="doc-footer">
    <div>Printed:{{doc.creation}}</div>
    <div>
      {% if doc.amended_from %}
        Amended From: {{ doc.amended_from }}
      {% endif %}
    </div>
    <div>{{ doc.name }}  Page 1</div>
  </div>

</div><!-- /.page -->
</body>
</html>
